UPDATE conteudos SET conteudo_texto = '<h2>Semântica e Coesão Textual</h2><p>Conceitos fundamentais para interpretação de textos e produção escrita em provas da Cesgranrio.</p><h3>📘 Semântica</h3><p>Estudo do <strong>significado das palavras</strong> e suas relações.</p><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><h4>🔤 Relações Semânticas</h4><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Relação</th><th style=''padding:10px;border:1px solid #ddd;''>Definição</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Sinônimos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Palavras com significados semelhantes</td><td style=''padding:10px;border:1px solid #ddd;''>feliz = contente</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Antônimos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Palavras com significados opostos</td><td style=''padding:10px;border:1px solid #ddd;''>bom ≠ mau</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Homônimos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Mesma grafia/som, significados diferentes</td><td style=''padding:10px;border:1px solid #ddd;''>manga (fruta) / manga (camisa)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Parônimos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Grafia/som parecidos, significados diferentes</td><td style=''padding:10px;border:1px solid #ddd;''>comprimento / cumprimento</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Polissemia</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Uma palavra com vários significados</td><td style=''padding:10px;border:1px solid #ddd;''>ponto (local, costura, nota)</td></tr></table></div><h4>🎯 Denotação vs Conotação</h4><div style=''display:flex;gap:15px;margin:15px 0;''><div style=''flex:1;background:#d4edda;padding:15px;border-radius:8px;border-left:4px solid #28a745;''><strong>📗 Denotação</strong><p>Sentido <strong>literal</strong>, dicionário.</p><p><em>"A cobra picou o homem."</em></p></div><div style=''flex:1;background:#fff3cd;padding:15px;border-radius:8px;border-left:4px solid #ffc107;''><strong>📙 Conotação</strong><p>Sentido <strong>figurado</strong>, subjetivo.</p><p><em>"Aquela mulher é uma cobra."</em></p></div></div><h3>🔗 Coesão Textual</h3><p>Mecanismos que <strong>conectam</strong> as partes do texto, garantindo fluidez e continuidade.</p><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><h4>📌 Tipos de Coesão</h4><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Conectivos</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Adição</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Acrescentar ideias</td><td style=''padding:10px;border:1px solid #ddd;''>e, também, além disso, ademais</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Oposição</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Contrastar ideias</td><td style=''padding:10px;border:1px solid #ddd;''>mas, porém, contudo, entretanto</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Causa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Indicar motivo</td><td style=''padding:10px;border:1px solid #ddd;''>porque, pois, já que, visto que</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Consequência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Indicar resultado</td><td style=''padding:10px;border:1px solid #ddd;''>logo, portanto, assim, por isso</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Condição</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Estabelecer hipótese</td><td style=''padding:10px;border:1px solid #ddd;''>se, caso, desde que, contanto que</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Tempo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Situar cronologicamente</td><td style=''padding:10px;border:1px solid #ddd;''>quando, enquanto, após, antes</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Finalidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Indicar objetivo</td><td style=''padding:10px;border:1px solid #ddd;''>para, a fim de, com o intuito de</td></tr></table></div><h4>🔄 Coesão Referencial</h4><p>Retoma ou antecipa elementos do texto:</p><ul><li><strong>Anáfora:</strong> Retoma algo já dito → <em>"A Petrobras investiu bilhões. <u>A empresa</u> é líder no setor."</em></li><li><strong>Catáfora:</strong> Antecipa algo → <em>"É <u>este</u> o problema: falta investimento."</em></li><li><strong>Elipse:</strong> Omissão de termo já mencionado → <em>"João estudou muito. [Ø] Passou no concurso."</em></li></ul><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A Cesgranrio adora pedir o <strong>valor semântico dos conectivos</strong>. Memorize a tabela acima!</p><p>Exemplo de questão: <em>"O conectivo ''porém'' estabelece relação de..."</em> → <strong>Oposição/Adversidade</strong></p></div><h3>🎯 Coerência Textual</h3><p>Diferente da coesão, a <strong>coerência</strong> é o sentido lógico do texto:</p><ul><li><strong>Não contradição:</strong> Ideias não podem se contradizer.</li><li><strong>Progressão:</strong> O texto deve avançar, trazer informações novas.</li><li><strong>Relação:</strong> As ideias devem ter conexão lógica.</li></ul>', video_url = 'https://www.youtube.com/watch?v=QjG5P8Xvp5M' WHERE titulo = 'Resumo: Semântica e Coesão';

UPDATE conteudos SET conteudo_texto = '<h2>Interpretação de Texto</h2><p>Técnicas e estratégias para compreender e analisar textos em provas de concursos.</p><h3>📖 Níveis de Leitura</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>1️⃣ Literal</strong><p>O que o texto DIZ explicitamente</p></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>2️⃣ Inferencial</strong><p>O que o texto SUGERE nas entrelinhas</p></div><div style=''flex:1;min-width:200px;background:#f8d7da;padding:15px;border-radius:8px;text-align:center;''><strong>3️⃣ Crítico</strong><p>ANÁLISE e julgamento do conteúdo</p></div></div><h3>🔍 Tipos de Questões</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#6c757d;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>O que pede</th><th style=''padding:10px;border:1px solid #ddd;''>Palavras-chave</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Compreensão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Informação explícita no texto</td><td style=''padding:10px;border:1px solid #ddd;''>"Segundo o texto", "O autor afirma"</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Inferência</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conclusão a partir do texto</td><td style=''padding:10px;border:1px solid #ddd;''>"Infere-se", "Depreende-se", "Conclui-se"</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Vocabulário</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Significado de palavra no contexto</td><td style=''padding:10px;border:1px solid #ddd;''>"O termo X significa", "Pode ser substituído por"</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Ideia Central</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Tema principal do texto</td><td style=''padding:10px;border:1px solid #ddd;''>"O texto trata de", "A ideia principal"</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Intenção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Objetivo do autor</td><td style=''padding:10px;border:1px solid #ddd;''>"O autor pretende", "A finalidade do texto"</td></tr></table></div><h3>📝 Tipologia Textual</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Características</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Narrativo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Contar história</td><td style=''padding:10px;border:1px solid #ddd;''>Personagens, tempo, espaço, enredo</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Descritivo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Detalhar características</td><td style=''padding:10px;border:1px solid #ddd;''>Adjetivos, detalhes, sensações</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Dissertativo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Argumentar/expor ideias</td><td style=''padding:10px;border:1px solid #ddd;''>Tese, argumentos, conclusão</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Injuntivo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Instruir/orientar</td><td style=''padding:10px;border:1px solid #ddd;''>Verbos no imperativo, instruções</td></tr></table></div><h3>🎯 Estratégia de Resolução</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #28a745;''><h4>✅ Passo a Passo</h4><ol><li><strong>Leia a questão primeiro</strong> → Saiba o que procurar.</li><li><strong>Leia o texto com atenção</strong> → Grife palavras-chave.</li><li><strong>Identifique o tema central</strong> → Geralmente no 1º parágrafo.</li><li><strong>Volte ao texto</strong> → Confirme cada alternativa.</li><li><strong>Elimine absurdos</strong> → Descarte alternativas claramente erradas.</li></ol></div><div style=''background:#f8d7da;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #dc3545;''><h4>❌ Armadilhas Comuns</h4><ul><li><strong>Extrapolação:</strong> Alternativa vai além do texto.</li><li><strong>Redução:</strong> Alternativa pega só uma parte do texto.</li><li><strong>Contradição:</strong> Alternativa diz o oposto do texto.</li><li><strong>Palavras fortes:</strong> "sempre", "nunca", "todos" → Desconfie!</li></ul></div><h3>💡 Figuras de Linguagem</h3><table style=''width:100%;border-collapse:collapse;margin:15px 0;''><tr style=''background:#6f42c1;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Figura</th><th style=''padding:10px;border:1px solid #ddd;''>Definição</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Metáfora</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Comparação implícita</td><td style=''padding:10px;border:1px solid #ddd;''>"A vida é uma viagem."</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Metonímia</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Substituição por proximidade</td><td style=''padding:10px;border:1px solid #ddd;''>"Li Machado de Assis." (a obra)</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Ironia</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Dizer o contrário</td><td style=''padding:10px;border:1px solid #ddd;''>"Que belo serviço!" (péssimo)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Hipérbole</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Exagero intencional</td><td style=''padding:10px;border:1px solid #ddd;''>"Estou morrendo de fome."</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Eufemismo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Suavizar expressão</td><td style=''padding:10px;border:1px solid #ddd;''>"Ele foi desta para melhor." (morreu)</td></tr></table>', video_url = 'https://www.youtube.com/watch?v=HKzGnxKBfEE' WHERE titulo = 'Resumo: Interpretação de Texto';

UPDATE conteudos SET conteudo_texto = '<h2>Gramática Essencial</h2><p>Os principais tópicos gramaticais cobrados em concursos da Cesgranrio.</p><h3>📚 Classes de Palavras</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Classe</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Substantivo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Nomeia seres e coisas</td><td style=''padding:10px;border:1px solid #ddd;''>petróleo, empresa, Brasil</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Adjetivo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Qualifica o substantivo</td><td style=''padding:10px;border:1px solid #ddd;''>eficiente, brasileiro, grande</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Verbo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Indica ação, estado, fenômeno</td><td style=''padding:10px;border:1px solid #ddd;''>produzir, ser, chover</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Advérbio</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Modifica verbo, adj. ou outro adv.</td><td style=''padding:10px;border:1px solid #ddd;''>muito, bem, rapidamente</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Pronome</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Substitui ou acompanha o nome</td><td style=''padding:10px;border:1px solid #ddd;''>ele, seu, aquele, que</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Preposição</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Liga termos</td><td style=''padding:10px;border:1px solid #ddd;''>de, para, com, em, a</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Conjunção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Liga orações</td><td style=''padding:10px;border:1px solid #ddd;''>e, mas, porque, se</td></tr></table></div><h3>✍️ Concordância Verbal</h3><p>O verbo concorda com o sujeito em <strong>número</strong> e <strong>pessoa</strong>.</p><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><h4>📌 Regras Importantes</h4><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Caso</th><th style=''padding:10px;border:1px solid #ddd;''>Regra</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Sujeito composto</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Verbo no plural</td><td style=''padding:10px;border:1px solid #ddd;''>João e Maria <u>estudam</u>.</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Expressão partitiva</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Singular ou plural</td><td style=''padding:10px;border:1px solid #ddd;''>A maioria dos alunos <u>passou/passaram</u>.</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Porcentagem</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Concorda com o termo próximo</td><td style=''padding:10px;border:1px solid #ddd;''>50% da turma <u>passou</u>. / 50% dos alunos <u>passaram</u>.</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Verbo HAVER (existir)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Sempre singular</td><td style=''padding:10px;border:1px solid #ddd;''><u>Havia</u> muitas pessoas. ✅</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Verbo FAZER (tempo)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Sempre singular</td><td style=''padding:10px;border:1px solid #ddd;''><u>Faz</u> dois anos que trabalho aqui. ✅</td></tr></table></div><h3>✍️ Concordância Nominal</h3><p>Adjetivos, artigos e pronomes concordam com o substantivo em <strong>gênero</strong> e <strong>número</strong>.</p><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #ffc107;''><h4>⚠️ Casos Especiais</h4><ul><li><strong>É proibido / É necessário:</strong> Sem artigo = invariável → <em>"É proibido entrada."</em></li><li><strong>Com artigo:</strong> Variável → <em>"É proibida a entrada."</em></li><li><strong>Anexo/Obrigado/Mesmo:</strong> Concordam com o substantivo → <em>"Seguem anexas as faturas."</em></li><li><strong>Meio (advérbio):</strong> Invariável → <em>"Ela está meio cansada."</em></li><li><strong>Bastante (advérbio):</strong> Invariável → <em>"Eles são bastante inteligentes."</em></li></ul></div><h3>🎯 Regência Verbal</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#6c757d;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Verbo</th><th style=''padding:10px;border:1px solid #ddd;''>Regência</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo Correto</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Assistir (ver)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transitivo indireto (A)</td><td style=''padding:10px;border:1px solid #ddd;''>Assisti <u>ao</u> filme. ✅</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Visar (objetivar)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transitivo indireto (A)</td><td style=''padding:10px;border:1px solid #ddd;''>Viso <u>ao</u> cargo. ✅</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Obedecer</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transitivo indireto (A)</td><td style=''padding:10px;border:1px solid #ddd;''>Obedeço <u>às</u> regras. ✅</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Preferir</strong></td><td style=''padding:10px;border:1px solid #ddd;''>X a Y (sem "do que")</td><td style=''padding:10px;border:1px solid #ddd;''>Prefiro café <u>a</u> chá. ✅</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Implicar (acarretar)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transitivo direto</td><td style=''padding:10px;border:1px solid #ddd;''>Isso implica <u>mudanças</u>. ✅</td></tr></table></div><h3>📍 Crase</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>✅ USA CRASE</h4><ul><li>Antes de palavras femininas</li><li>Locuções femininas (às vezes, à noite)</li><li>Indicação de horas</li><li>"À moda de" (mesmo implícito)</li></ul></div><div style=''flex:1;min-width:200px;background:#f8d7da;padding:15px;border-radius:8px;''><h4>❌ NÃO USA</h4><ul><li>Antes de palavras masculinas</li><li>Antes de verbos</li><li>Antes de pronomes pessoais</li><li>Antes de "casa" e "terra" (sem especificador)</li></ul></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Macete da Crase</h4><p>Troque a palavra feminina por uma masculina:</p><ul><li>Se aparecer <strong>"AO"</strong> → tem crase: <em>"Fui à praia" → "Fui ao parque"</em> ✅</li><li>Se aparecer <strong>"O"</strong> → não tem crase: <em>"Vi a menina" → "Vi o menino"</em> ❌</li></ul></div>', video_url = 'https://www.youtube.com/watch?v=Z1PwmGMqlFU' WHERE titulo = 'Resumo: Gramática Essencial';